import{_ as t,o,c as a,ak as s}from"./chunks/framework.BwzOvEE0.js";const p=JSON.parse('{"title":"What is mcp-exec?","description":"The problem mcp-exec solves, how it works architecturally, and when to use it.","frontmatter":{"description":"The problem mcp-exec solves, how it works architecturally, and when to use it."},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1778311268000}'),n={name:"guide/introduction.md"};function i(r,e,l,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="what-is-mcp-exec" tabindex="-1">What is mcp-exec? <a class="header-anchor" href="#what-is-mcp-exec" aria-label="Permalink to &quot;What is mcp-exec?&quot;">​</a></h1><h2 id="you-ve-been-here" tabindex="-1">You&#39;ve been here <a class="header-anchor" href="#you-ve-been-here" aria-label="Permalink to &quot;You&#39;ve been here&quot;">​</a></h2><p>Mid-workflow. Claude&#39;s working. Three more tool calls to go. Then:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ Searching QuickBooks... 847 invoices found (context: +14,200 tokens)</span></span>
<span class="line"><span>✓ Filtering overdue... 23 invoices (context: +8,100 tokens)</span></span>
<span class="line"><span>✓ Fetching customer details...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠  Claude AI Usage Limit Reached</span></span>
<span class="line"><span>   You&#39;ve reached your usage limit and will be able to resume in 5 hours.</span></span></code></pre></div><p>The tool calls worked. Claude ran out of room to think.</p><p>This isn&#39;t a fluke — it&#39;s a structural problem. Every intermediate result from every tool call flows directly into the context window. By the time Claude is halfway through a real workflow, the context is packed with raw API responses that Claude already processed and no longer needs. The model hits its limit not because the task was too hard, but because the conversation got too long.</p><p>mcp-exec fixes this architecturally: intermediate data never touches context.</p><h2 id="two-root-causes-of-token-bloat" tabindex="-1">Two root causes of token bloat <a class="header-anchor" href="#two-root-causes-of-token-bloat" aria-label="Permalink to &quot;Two root causes of token bloat&quot;">​</a></h2><p><strong>Schema bloat</strong> — Every MCP server loads its full tool schemas at startup. A single server with 20 tools can add 40,000 tokens before Claude makes a single call. With multiple servers connected, you can exhaust a meaningful fraction of the context window just by opening a session.</p><p><strong>Result bloat</strong> — Raw API responses are verbose by nature. A search returning 847 invoices doesn&#39;t return 847 numbers — it returns 847 objects with IDs, timestamps, metadata, line items, and audit fields. A single call that fetches emails, PRs, or document bodies can flood 10,000–20,000 tokens into context. Chained tool calls multiply this rapidly.</p><h2 id="the-solution" tabindex="-1">The solution <a class="header-anchor" href="#the-solution" aria-label="Permalink to &quot;The solution&quot;">​</a></h2><p>mcp-exec adds two tools to Claude Code:</p><p><strong><code>tools(query)</code></strong> — searches your connected MCP servers and returns trimmed summaries. A description, a name, and a signature. Full schemas never touch the context window. Discovering what tools are available costs tens of tokens instead of tens of thousands.</p><p><strong><code>exec(code, runtime)</code></strong> — runs code in an OS-level sandbox. MCP servers are importable as modules inside the sandbox. Multiple tool calls, data processing, filtering, and aggregation happen entirely inside the sandbox — only the final return value comes back to Claude.</p><p>The sandbox is opaque to Claude by design. Claude sees the input (the code it sent) and the output (the final return value). Everything in between — the raw API responses, the intermediate arrays, the filtered lists, the fetched document bodies — stays inside the sandbox and is discarded when the call completes.</p><h3 id="runtimes" tabindex="-1">Runtimes <a class="header-anchor" href="#runtimes" aria-label="Permalink to &quot;Runtimes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Runtime</th><th>State</th><th>Use for</th></tr></thead><tbody><tr><td><code>&quot;node&quot;</code></td><td>Persistent (<code>globalThis</code>)</td><td>MCP orchestration, multi-step workflows</td></tr><tr><td><code>&quot;bash&quot;</code></td><td>Stateless</td><td>Unix pipelines, <code>jq</code>, <code>awk</code>, post-processing</td></tr><tr><td><code>&quot;python&quot;</code></td><td>Stateless (<code>uv run --isolated</code>)</td><td>Data analysis, pandas, arbitrary PyPI packages via PEP 723</td></tr></tbody></table><h2 id="before-after" tabindex="-1">Before / After <a class="header-anchor" href="#before-after" aria-label="Permalink to &quot;Before / After&quot;">​</a></h2><p><strong>Without mcp-exec</strong>, a workflow that fetches invoices, filters by status, looks up customer details, and drafts an email might look like this in the context window:</p><ol><li><code>searchInvoices()</code> → 847 invoice objects → ~14,200 tokens added</li><li>Claude filters in-context → filtered list displayed → ~2,000 tokens</li><li><code>getCustomer()</code> × 23 calls → 23 customer records → ~8,100 tokens added</li><li><code>createDraft()</code> → draft confirmation → ~400 tokens</li></ol><p>Total: ~25,000 tokens. And that&#39;s before Claude writes a word of the final response.</p><p><strong>With mcp-exec</strong>, the same workflow looks like this:</p><ol><li><code>exec({ runtime: &quot;node&quot;, code: &quot;...&quot; })</code> → all four steps happen in the sandbox → <code>&quot;Draft created — 23 invoices&quot;</code> → ~80 tokens added</li></ol><p>Total: ~80 tokens. The 847 invoice objects, the 23 customer records, and all the intermediate filtering never appear in context.</p><p>The 99% reduction in the headline isn&#39;t a compression trick. The data was simply never there.</p><h2 id="when-not-to-use-mcp-exec" tabindex="-1">When NOT to use mcp-exec <a class="header-anchor" href="#when-not-to-use-mcp-exec" aria-label="Permalink to &quot;When NOT to use mcp-exec&quot;">​</a></h2><p>mcp-exec is the right tool for multi-step workflows with large intermediate data. It&#39;s not always the right tool:</p><ul><li><strong>Single-tool calls where the result is small and you want it visible in context</strong> — if you&#39;re fetching one record and you want Claude to reason about its contents directly, keep it in context.</li><li><strong>When you need to display raw API output verbatim to the user</strong> — if the goal is to show the user a list of items, put that list in context where it can be rendered.</li><li><strong>Interactive tool calls where the user needs to confirm intermediate results</strong> — if the workflow requires human review at each step, the sandbox&#39;s opacity works against you. Keep those calls visible.</li></ul><p>Use exec for orchestration. Use direct tool calls for display and confirmation.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/mcp-exec/guide/installation.html">Install mcp-exec →</a></li><li><a href="/mcp-exec/guide/getting-started.html">Run your first exec() call →</a></li></ul>`,31)])])}const m=t(n,[["render",i]]);export{p as __pageData,m as default};
